1	package agent
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7		"strings"
8	
9		"github.com/DocumentDrivenDX/ddx/internal/bead"
10		"github.com/DocumentDrivenDX/ddx/internal/config"
11		agentlib "github.com/DocumentDrivenDX/fizeau"
12	)
13	
14	// PreClaimIntakePromptSource identifies the pre-claim complexity-eval
15	// dispatch in session logs and tests.
16	const PreClaimIntakePromptSource = "bead-lifecycle-intake"
17	
18	type preClaimIntakePromptEnvelope struct {
19		Title         string                  `json:"title"`
20		Description   string                  `json:"description"`
21		Acceptance    string                  `json:"acceptance"`
22		Labels        []string                `json:"labels"`
23		PriorAttempts []preClaimIntakeAttempt `json:"prior_attempts"`
24		Depth         int                     `json:"depth"`
25		Parent        string                  `json:"parent,omitempty"`
26		Dependencies  []string                `json:"dependencies,omitempty"`
27	}
28	
29	type preClaimIntakeAttempt struct {
30		Status    string `json:"status"`
31		Rationale string `json:"rationale,omitempty"`
32	}
33	
34	type preClaimIntakePromptResult struct {
35		Classification string                      `json:"classification"`
36		Confidence     any                         `json:"confidence,omitempty"`
37		Reasoning      string                      `json:"reasoning,omitempty"`
38		Rewrite        preClaimIntakePromptRewrite `json:"rewrite,omitempty"`
39	}
40	
41	type preClaimIntakePromptRewrite struct {
42		Description   string   `json:"description,omitempty"`
43		Acceptance    string   `json:"acceptance,omitempty"`
44		ChangedFields []string `json:"changed_fields,omitempty"`
45	}
46	
47	// preClaimReadinessPromptResult is the canonical readiness JSON schema returned
48	// by skills that use the FEAT-010/ADR-023 outcome vocabulary.
49	type preClaimReadinessPromptResult struct {
50		Outcome string                      `json:"outcome"`
51		Reason  string                      `json:"reason,omitempty"`
52		Detail  string                      `json:"detail,omitempty"`
53		Rewrite preClaimIntakePromptRewrite `json:"rewrite,omitempty"`
54	}
55	
56	// NewPreClaimIntakeHook constructs the bead-intake complexity gate used
57	// before claim in the work / execute-loop paths. The hook evaluates the bead
58	// using the repository's triage prompt and returns one of the typed intake
59	// outcomes so the loop can decide whether to claim or skip the candidate.
60	//
61	// The hook preserves operator-supplied passthrough constraints. When the
62	// resolved route cannot satisfy the strong splitter floor, it returns an
63	// actionable-but-blocking result with agent_power_unsatisfied in the detail so
64	// the loop can skip the bead instead of attempting weak decomposition.
65	func NewPreClaimIntakeHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
66		return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
67			if ctx != nil {
68				if err := ctx.Err(); err != nil {
69					return PreClaimIntakeResult{}, err
70				}
71			}
72			if strings.TrimSpace(projectRoot) == "" {
73				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
74			}
75			if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
76				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: %w", err)
77			}
78			if store == nil {
79				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
80			}
81	
82			b, err := store.Get(beadID)
83			if err != nil {
84				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
85			}
86	
87			prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
88			if err != nil {
89				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
90			}
91	
92			strongMinPower := resolveStrongSplitterMinPower(ctx, projectRoot, svc)
93			if rcfg.MinPower() > strongMinPower {
94				strongMinPower = rcfg.MinPower()
95			}
96	
97			runtime := AgentRunRuntime{
98				Prompt:          prompt,
99				WorkDir:         projectRoot,
100				PromptSource:    PreClaimIntakePromptSource,
101				ProfileOverride: "smart",
102				ClearMaxPower:   true,
103			}
104			if strongMinPower > 0 {
105				runtime.MinPowerOverride = strongMinPower
106			}
107			payload, err := dispatchPreClaimIntakePayload(ctx, projectRoot, svc, runner, rcfg, runtime, strongMinPower)
108			if err != nil {
109				if isStrongPowerUnsatisfiedError(err) {
110					return PreClaimIntakeResult{
111						Outcome: PreClaimIntakeAmbiguousNeedsHuman,
112						Detail:  "pre-claim intake requires a smart/frontier route but no viable model was available",
113					}, nil
114				}
115				return PreClaimIntakeResult{}, err
116			}
117	
118			return decodePreClaimIntakePayloadResult(payload)
119		}
120	}
121	
122	func dispatchPreClaimIntakePayload(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime, strongMinPower int) (string, error) {
123		payload, err := dispatchPreClaimIntakePayloadOnce(ctx, projectRoot, svc, runner, rcfg, runtime)
124		if err == nil {
125			return payload, nil
126		}
127		if runtime.ProfileOverride != "smart" || strongMinPower > 0 || !isSmartProfileUnavailableError(err) {
128			return "", err
129		}
130	
131		runtime.ProfileOverride = DefaultRoutingProfile
132		return dispatchPreClaimIntakePayloadOnce(ctx, projectRoot, svc, runner, rcfg, runtime)
133	}
134	
135	func dispatchPreClaimIntakePayloadOnce(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (string, error) {
136		result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)
137		if err != nil {
138			return "", fmt.Errorf("pre-claim intake: dispatch: %w", err)
139		}
140		return intakeResultPayload(result)
141	}
142	
143	func buildPreClaimIntakePrompt(projectRoot string, store BeadReader, b *bead.Bead) (string, error) {
144		env := preClaimIntakePromptEnvelope{
145			Title:         strings.TrimSpace(b.Title),
146			Description:   strings.TrimSpace(b.Description),
147			Acceptance:    strings.TrimSpace(b.Acceptance),
148			Labels:        append([]string(nil), b.Labels...),
149			PriorAttempts: []preClaimIntakeAttempt{},
150			Depth:         beadDecompositionDepth(projectRoot, b),
151			Parent:        strings.TrimSpace(b.Parent),
152			Dependencies:  append([]string(nil), b.DepIDs()...),
153		}
154	
155		// Prior attempts are optional for the gate. If bead history is available,
156		// include the last few attempt/result summaries to help the classifier
157		// distinguish a first-pass atomic bead from repeated decomposition.
158		if store != nil {
159			if eventStore, ok := any(store).(interface {
160				Events(id string) ([]bead.BeadEvent, error)
161			}); ok {
162				if events, err := eventStore.Events(b.ID); err == nil && len(events) > 0 {
163					for i := len(events) - 1; i >= 0 && len(env.PriorAttempts) < 5; i-- {
164						ev := events[i]
165						if ev.Kind != "bead.result" && ev.Kind != "execute-bead" {
166							continue
167						}
168						env.PriorAttempts = append(env.PriorAttempts, preClaimIntakeAttempt{
169							Status:    strings.TrimSpace(ev.Summary),
170							Rationale: strings.TrimSpace(ev.Body),
171						})
172					}
173				}
174			}
175		}
176	
177		body, err := json.MarshalIndent(env, "", "  ")
178		if err != nil {
179			return "", err
180		}
181	
182		var sb strings.Builder
183		sb.WriteString("MODE: intake\n")
184		sb.WriteString("You are evaluating whether this bead is atomic, decomposable, ambiguous, or safely refinable before claim.\n")
185		sb.WriteString("Use rewritten only when you can preserve the bead's intent and return safe description/acceptance updates without inventing behavior, choosing product semantics, widening scope, or dropping acceptance criteria.\n")
186		sb.WriteString("If the bead cannot be safely refined, classify it as ambiguous.\n")
187		sb.WriteString("Return exactly one JSON object matching the intake schema with classification, confidence, reasoning, and optional rewrite fields.\n")
188		sb.WriteString("When classification is rewritten, include rewrite.changed_fields, rewrite.description, and rewrite.acceptance.\n")
189		sb.WriteString("Do not include prose or markdown.\n\n")
190		sb.WriteString("```json\n")
191		sb.Write(body)
192		sb.WriteString("\n```\n")
193		return sb.String(), nil
194	}
195	
196	func intakeResultPayload(result *Result) (string, error) {
197		if result == nil {
198			return "", fmt.Errorf("pre-claim intake: empty runner result")
199		}
200		text := strings.TrimSpace(result.CondensedOutput)
201		if text == "" {
202			text = strings.TrimSpace(result.Output)
203		}
204		if text == "" {
205			if strings.TrimSpace(result.Error) != "" {
206				return "", fmt.Errorf("pre-claim intake: runner error: %s", strings.TrimSpace(result.Error))
207			}
208			if result.ExitCode != 0 {
209				return "", fmt.Errorf("pre-claim intake: runner exited with code %d and empty output", result.ExitCode)
210			}
211			return "", fmt.Errorf("pre-claim intake: empty output")
212		}
213		candidate, ok := extractJSONCandidate(text)
214		if !ok {
215			return "", fmt.Errorf("pre-claim intake: no JSON object found")
216		}
217		return candidate, nil
218	}
219	
220	func normalizePreClaimIntakeRewriteFields(fields []string) []string {
221		if len(fields) == 0 {
222			return nil
223		}
224		seen := make(map[string]struct{}, len(fields))
225		out := make([]string, 0, len(fields))
226		for _, field := range fields {
227			field = strings.ToLower(strings.TrimSpace(field))
228			if field == "" {
229				continue
230			}
231			if _, ok := seen[field]; ok {
232				continue
233			}
234			seen[field] = struct{}{}
235			out = append(out, field)
236		}
237		return out
238	}
239	
240	func resolveStrongSplitterMinPower(ctx context.Context, projectRoot string, svc agentlib.FizeauService) int {
241		if svc == nil {
242			return 0
243		}
244	
245		models, err := svc.ListModels(ctx, agentlib.ModelFilter{})
246		if err != nil {
247			return 0
248		}
249		maxPower := 0
250		for _, m := range models {
251			if m.Power > maxPower {
252				maxPower = m.Power
253			}
254		}
255		return maxPower
256	}
257	
258	func isStrongPowerUnsatisfiedError(err error) bool {
259		if err == nil {
260			return false
261		}
262		switch ClassifyFailureMode("task_failed", 1, err.Error()) {
263		case FailureModeAgentPowerUnsatisfied, FailureModeBlockedByPassthroughConstraint:
264			return true
265		default:
266			return false
267		}
268	}
269	
270	func isSmartProfileUnavailableError(err error) bool {
271		if err == nil {
272			return false
273		}
274		msg := strings.ToLower(err.Error())
275		return strings.Contains(msg, "tier ≥ smart") ||
276			strings.Contains(msg, "tier >= smart") ||
277			strings.Contains(msg, "profile=smart") ||
278			strings.Contains(msg, "profile smart")
279	}
280	
281	// decodePreClaimIntakePayloadResult decodes a JSON payload into a PreClaimIntakeResult.
282	// It accepts both the legacy intake schema (classification field) and the canonical
283	// readiness schema (outcome field), converting both into the same decision model.
284	func decodePreClaimIntakePayloadResult(payload string) (PreClaimIntakeResult, error) {
285		var probe struct {
286			Classification string `json:"classification"`
287			Outcome        string `json:"outcome"`
288		}
289		if err := json.Unmarshal([]byte(payload), &probe); err != nil {
290			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
291		}
292		if probe.Outcome != "" {
293			return decodeCanonicalReadinessPayload(payload)
294		}
295		if probe.Classification != "" {
296			return decodeLegacyIntakePayload(payload)
297		}
298		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification or outcome field")
299	}
300	
301	func decodeCanonicalReadinessPayload(payload string) (PreClaimIntakeResult, error) {
302		var out preClaimReadinessPromptResult
303		if err := json.Unmarshal([]byte(payload), &out); err != nil {
304			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
305		}
306		detail := strings.TrimSpace(out.Reason)
307		if detail == "" {
308			detail = strings.TrimSpace(out.Detail)
309		}
310		rewrite := PreClaimIntakeRewrite{
311			Description:   strings.TrimSpace(out.Rewrite.Description),
312			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
313			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
314		}
315		switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
316		case "actionable_atomic":
317			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail}, nil
318		case "actionable_but_rewritten":
319			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, Rewrite: rewrite}, nil
320		case "too_large_decomposed":
321			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: detail}, nil
322		case "ambiguous_needs_human":
323			return PreClaimIntakeResult{Outcome: PreClaimIntakeAmbiguousNeedsHuman, Detail: detail}, nil
324		case "readiness_error", "system_unready":
325			// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
326			return PreClaimIntakeResult{Outcome: PreClaimIntakeError, Detail: detail}, nil
327		case "":
328			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
329		default:
330			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, ambiguous_needs_human, readiness_error, system_unready", out.Outcome)
331		}
332	}
333	
334	func decodeLegacyIntakePayload(payload string) (PreClaimIntakeResult, error) {
335		var out preClaimIntakePromptResult
336		if err := json.Unmarshal([]byte(payload), &out); err != nil {
337			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
338		}
339		switch strings.ToLower(strings.TrimSpace(out.Classification)) {
340		case "atomic":
341			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
342		case "rewritten":
343			return PreClaimIntakeResult{
