	for _, field := range normalized.ChangedFields {
		if _, ok := allowed[field]; !ok {
			return zero, fmt.Errorf("pre-claim intake rewrite: unsafe field %q", field)
		}
	}

	before := snapshotPreClaimIntakeRewrite(original.Description, original.Acceptance)

	oldDescription := strings.TrimSpace(original.Description)
	var preservedCommitments []string
	if hasString(normalized.ChangedFields, "description") {
		if normalized.Description == "" {
			return zero, fmt.Errorf("pre-claim intake rewrite: description rewrite missing")
		}
		if strings.EqualFold(strings.TrimSpace(normalized.Description), oldDescription) {
			return zero, fmt.Errorf("pre-claim intake rewrite: description unchanged")
		}
		if oldDescription != "" {
			preserved, ok := descriptionPreservesCommitments(oldDescription, normalized.Description)
			if !ok {
				return zero, fmt.Errorf("pre-claim intake rewrite: description drops explicit commitments")
			}
			preservedCommitments = preserved
		}
	} else if normalized.Description != "" {
		return zero, fmt.Errorf("pre-claim intake rewrite: description supplied without changed_fields")
	}

	oldAcceptance := strings.TrimSpace(original.Acceptance)
	if hasString(normalized.ChangedFields, "acceptance") {
		if normalized.Acceptance == "" {
			return zero, fmt.Errorf("pre-claim intake rewrite: acceptance rewrite missing")
		}
		if strings.EqualFold(strings.TrimSpace(normalized.Acceptance), oldAcceptance) {
			return zero, fmt.Errorf("pre-claim intake rewrite: acceptance unchanged")
		}
		if !acceptancePreservesCriteria(oldAcceptance, normalized.Acceptance) {
			return zero, fmt.Errorf("pre-claim intake rewrite: acceptance criteria dropped or altered")
		}
	} else if normalized.Acceptance != "" {
		return zero, fmt.Errorf("pre-claim intake rewrite: acceptance supplied without changed_fields")
	}

	afterDescription := oldDescription
	if containsString(normalized.ChangedFields, "description") {
		afterDescription = normalized.Description
	}
	afterAcceptance := oldAcceptance
	if containsString(normalized.ChangedFields, "acceptance") {
		afterAcceptance = normalized.Acceptance
	}
	after := snapshotPreClaimIntakeRewrite(afterDescription, afterAcceptance)
	return preClaimIntakeValidationResult{
		Rewrite:              normalized,
		Before:               before,
		After:                after,
		PreservedCommitments: preservedCommitments,
	}, nil
}

// extractDescriptionCommitments returns the explicit commitments embedded in a
// bead description that must be preserved by any replacement rewrite. These are
// NON-SCOPE section items, test function names, file references (path without
// trailing :line so updated line numbers are allowed), governing artifact refs
// (FEAT-NNN/ADR-NNN), and bead IDs (ddx-XXXXXXXX).
func extractDescriptionCommitments(text string) []string {
	var out []string
	seen := make(map[string]struct{})
	add := func(s string) {
		s = normalizeWhitespace(s)
		if s == "" {
			return
		}
		if _, ok := seen[s]; ok {
			return
		}
		seen[s] = struct{}{}
		out = append(out, s)
	}

	for _, item := range parseNonScopeItems(text) {
		add(item)
	}
	for _, m := range testNameRe.FindAllString(text, -1) {
		add(m)
	}
	for _, m := range fileLineRe.FindAllString(text, -1) {
		// Strip :NNN suffix so updated line numbers in the replacement are accepted.
		if colon := strings.LastIndex(m, ":"); colon > 0 {
			m = m[:colon]
		}
		add(m)
	}
	for _, m := range governingArtifactRe.FindAllString(text, -1) {
		add(m)
	}
	for _, m := range beadIDRe.FindAllString(text, -1) {
		add(m)
	}
	return out
}

// parseNonScopeItems extracts listed items from the NON-SCOPE section of a bead
// description. The section ends at the next recognized section header.
func parseNonScopeItems(text string) []string {
	var out []string
	inNonScope := false
	for _, line := range strings.Split(text, "\n") {
		trimmed := strings.TrimSpace(line)
		upper := strings.ToUpper(trimmed)
		if upper == "NON-SCOPE" || upper == "NON-SCOPE:" {
			inNonScope = true
			continue
		}
		if !inNonScope {
			continue
		}
		if trimmed == "" {
			continue
		}
		if isDescriptionSectionHeader(upper) {
			inNonScope = false
			continue
		}
		item := trimmed
		if len(item) > 0 && (item[0] == '-' || item[0] == '*' || item[0] == '+') {
			item = strings.TrimSpace(item[1:])
		}
		if item != "" {
			out = append(out, normalizeWhitespace(item))
		}
	}
	return out
}

func isDescriptionSectionHeader(upper string) bool {
	switch upper {
	case "PROBLEM", "ROOT CAUSE", "PROPOSED FIX", "NON-SCOPE",
		"DEPENDENCIES", "PARENT + DEPS", "CONTEXT", "BACKGROUND",
		"NOTES", "OPEN QUESTIONS", "ACCEPTANCE CRITERIA":
		return true
	}
	return false
}

// descriptionPreservesCommitments checks that all explicit commitments from
// oldDesc are present in newDesc. Returns the list of verified commitments and
// whether all commitments pass. An empty commitment list always passes.
func descriptionPreservesCommitments(oldDesc, newDesc string) ([]string, bool) {
	commitments := extractDescriptionCommitments(oldDesc)
	if len(commitments) == 0 {
		return nil, true
	}
	var preserved []string
	for _, c := range commitments {
		if !strings.Contains(newDesc, c) {
			return preserved, false
		}
		preserved = append(preserved, c)
	}
	return preserved, true
}

