// TestPreClaimIntakeRewrite_AllowsCompressionReplacement verifies that a replacement
// description can remove stale/noisy old prose when explicit commitments and durable
// anchors are preserved (FEAT-010/ADR-023 validated replacement policy).
func TestPreClaimIntakeRewrite_AllowsCompressionReplacement(t *testing.T) {
	original := &bead.Bead{
		Description: "PROBLEM\n" +
			"cli/internal/agent/preclaim_intake_rewrite.go:118 forces append-only.\n\n" +
			"ROOT CAUSE\n" +
			"Historical notes from 2025: tried fix A, tried fix B, see chat thread for context.\n" +
			"The real issue is at cli/internal/agent/preclaim_intake_rewrite.go:119.\n\n" +
			"NON-SCOPE\n" +
			"Do not rename PreClaimIntakeRewrite\n" +
			"Do not implement child decomposition\n\n" +
			"PROPOSED FIX\n" +
			"Replace substring check with commitment-based validation per FEAT-010.\n",
		Acceptance: "1. TestPreClaimIntakeRewrite_AllowsCompressionReplacement passes\n" +
			"2. cd cli && go test ./internal/agent/... green\n",
	}

	// Compression: removes stale historical chat notes while keeping all commitments.
	compressed := "PROBLEM\n" +
		"cli/internal/agent/preclaim_intake_rewrite.go:119 enforces append-only contrary to FEAT-010.\n\n" +
		"NON-SCOPE\n" +
		"Do not rename PreClaimIntakeRewrite\n" +
		"Do not implement child decomposition\n\n" +
		"PROPOSED FIX\n" +
		"Replace substring check with commitment-based validation.\n"

	vr, err := validateAndApplyPreClaimIntakeRewrite(original, PreClaimIntakeRewrite{
		Description:   compressed,
		ChangedFields: []string{"description"},
	})
	require.NoError(t, err)
	assert.Equal(t, compressed, vr.Rewrite.Description)
	assert.NotEmpty(t, vr.PreservedCommitments, "preserved commitments must be recorded")
	assert.Contains(t, vr.PreservedCommitments, "Do not rename PreClaimIntakeRewrite")
	assert.Contains(t, vr.PreservedCommitments, "Do not implement child decomposition")
	assert.Contains(t, vr.PreservedCommitments, "FEAT-010")
}

// TestPreClaimIntakeRewrite_AllowsExpansionReplacement verifies that a vague one-line
// description can expand into a standalone executable bead when the added content is
// grounded in durable context and does not invent product semantics.
func TestPreClaimIntakeRewrite_AllowsExpansionReplacement(t *testing.T) {
	original := &bead.Bead{
		// Vague: no commitments to extract.
		Description: "Fix failing intake tests",
		Acceptance:  "1. tests pass\n2. lefthook run pre-commit green\n",
