	})
	require.NoError(t, err)
	assert.Equal(t, expanded, vr.Rewrite.Description)
	// Old description had no extractable commitments; preserved list must be empty.
	assert.Empty(t, vr.PreservedCommitments)
}

// TestPreClaimIntakeRewrite_RejectsDeletedCommitment verifies that non-scope items,
// governing artifact references, named files/tests, and bead dependencies cannot be
// silently removed by a replacement rewrite.
func TestPreClaimIntakeRewrite_RejectsDeletedCommitment(t *testing.T) {
	tests := []struct {
		name    string
		oldDesc string
		newDesc string
	}{
		{
			name:    "removes_non_scope_item",
			oldDesc: "PROBLEM\nfoo\n\nNON-SCOPE\nDo not change the public API\n",
			newDesc: "PROBLEM\nfoo improved\n",
		},
		{
			name:    "removes_governing_ref",
			oldDesc: "PROBLEM\nfoo\n\nROOT CAUSE\nsee FEAT-010 for policy.\n",
			newDesc: "PROBLEM\nfoo improved without governing reference.\n",
		},
		{
			name:    "removes_file_reference",
			oldDesc: "ROOT CAUSE\ncli/internal/agent/preclaim_intake_rewrite.go:118 is wrong.\n",
			newDesc: "ROOT CAUSE\nthe function is wrong.\n",
		},
		{
			name:    "removes_test_name",
			oldDesc: "PROPOSED FIX\nMust satisfy TestPreClaimIntakeRewrite_AllowsCompressionReplacement.\n",
			newDesc: "PROPOSED FIX\nFix the tests.\n",
		},
		{
