			oldDesc: "PARENT + DEPS\nDepends on ddx-a41e6fbb.\n",
			newDesc: "PARENT + DEPS\nNo deps.\n",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			original := &bead.Bead{
