				ChangedFields: []string{"description"},
			})
			require.Error(t, err)
			assert.Contains(t, err.Error(), "explicit commitments")
		})
	}
}

// TestPreClaimIntakeRewrite_RecordsReplacementEvidence verifies that intake-rewritten
// records changed fields, rationale, before/after hashes, and preservation evidence
// sufficient to audit the original text without duplicating it into the replacement body.
func TestPreClaimIntakeRewrite_RecordsReplacementEvidence(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{
		ID:     "ddx-ev1denc1",
		Title:  "Evidence test",
		Status: bead.StatusOpen,
		Description: "PROBLEM\n" +
			"cli/internal/agent/preclaim_intake_rewrite.go:118 is stale.\n\n" +
			"NON-SCOPE\n" +
			"Do not change public API\n",
		Acceptance: "1. TestFoo\n2. cd cli && go test ./...\n",
	}
	require.NoError(t, store.Create(b))

	newDesc := "PROBLEM\n" +
		"cli/internal/agent/preclaim_intake_rewrite.go:155 now uses commitment-based check.\n\n" +
		"NON-SCOPE\n" +
		"Do not change public API\n"

	intake := PreClaimIntakeResult{
		Outcome: PreClaimIntakeActionableButRewritten,
		Detail:  "compressed stale prose, updated line reference",
		Rewrite: PreClaimIntakeRewrite{
			Description:   newDesc,
			ChangedFields: []string{"description"},
		},
	}

	require.NoError(t, applyPreClaimIntakeRewrite(store, b.ID, "test-actor", intake, time.Now()))

	events, err := store.Events(b.ID)
	require.NoError(t, err)

	var ev *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "intake-rewritten" {
			ev = &events[i]
			break
		}
	}
	require.NotNil(t, ev, "intake-rewritten event must be recorded")

	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(ev.Body), &body))

	// Must record changed fields, rationale, before/after hashes.
	assert.Equal(t, "compressed stale prose, updated line reference", body["rationale"])
	assert.NotNil(t, body["changed_fields"])
	assert.NotNil(t, body["before"])
	assert.NotNil(t, body["after"])

	// Must include preservation evidence.
	assert.NotNil(t, body["preserved_commitments"], "preservation evidence must be recorded in intake-rewritten event")
	preserved, ok := body["preserved_commitments"].([]any)
	require.True(t, ok, "preserved_commitments must be a list")
	assert.NotEmpty(t, preserved)

	// Before/after hashes must differ (description changed).
	before := body["before"].(map[string]any)
	after := body["after"].(map[string]any)
	assert.NotEqual(t, before["description_sha256"], after["description_sha256"])

	// Must NOT embed the original description text verbatim in the event body.
	assert.NotContains(t, ev.Body, "is stale")
}

